import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

export default function Home() {
  const [services, setServices] = useState([]);
  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    API.get('/services').then(res => setServices(res.data));
  }, []);

  return (
    <div style={styles.container}>
      <div style={styles.hero}>
        <h1>Book Your Appointment Online</h1>
        <p>Find services and book slots instantly — no phone calls needed.</p>
      </div>
      <h2 style={styles.heading}>Available Services</h2>
      <div style={styles.grid}>
        {services.length === 0 && <p>No services available yet.</p>}
        {services.map(s => (
          <div key={s._id} style={styles.card}>
            <h3 style={styles.serviceName}>{s.name}</h3>
            <p style={styles.desc}>{s.description}</p>
            <p>⏱ {s.duration} mins &nbsp;|&nbsp; ₹{s.price}</p>
            <p style={styles.provider}>👤 {s.provider?.name}</p>
            <button style={styles.btn}
              onClick={() => user ? navigate(`/book/${s._id}`) : navigate('/login')}>
              Book Now
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  container: { padding: '20px 40px', background: '#f0f4ff', minHeight: '90vh' },
  hero: { background: '#1a73e8', color: '#fff', padding: '40px', borderRadius: '12px', textAlign: 'center', marginBottom: '30px' },
  heading: { marginBottom: '20px', color: '#333' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '20px' },
  card: { background: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 2px 10px rgba(0,0,0,0.08)' },
  serviceName: { color: '#1a73e8', margin: '0 0 8px' },
  desc: { color: '#666', fontSize: '14px' },
  provider: { fontSize: '13px', color: '#888' },
  btn: { marginTop: '12px', width: '100%', background: '#1a73e8', color: '#fff', border: 'none', padding: '10px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }
};
